# =============================================================================
# MERGE INTO JSON FILES
# =============================================================================
all_langs = {
    'en': offer_en,
    'de': offer_de,
    'hr': offer_hr,
    'fr': offer_fr,
    'es': offer_es,
    'it': offer_it,
}

for lang_code, new_keys in all_langs.items():
    filepath = os.path.join(I18N_DIR, f'{lang_code}.json')
    with open(filepath, 'r', encoding='utf-8') as f:
        existing = json.load(f)

    existing.update(new_keys)

    with open(filepath, 'w', encoding='utf-8') as f:
        json.dump(existing, f, indent=2, ensure_ascii=False)

    print(f"Updated {lang_code}.json ({len(new_keys)} new top-level keys)")

print("\nDone. All 6 language files updated with offer page translations.")
